executeFunc((function changeReferenceCarNewEditForm(){const formName="car_brand_form";let $form=document.querySelector(`form[name='${formName}']`);if($form){let $nameInput=$form.querySelector(`#${formName}_name_value`);if($nameInput&&!$nameInput.value){$nameInput.addEventListener("input",(function(){let $urlInput=$form.querySelector(`#${formName}_name_url`);if($urlInput){$urlInput.value=$nameInput.value.toLowerCase().replace(/$/g,"").replace(/$/g,"").replace(/ /g,"-").replace(/\//g,"-")}}))}}}));